import type { AccountDto } from '../services/master/models';
import {
  getLookupWarningReason,
  shouldShowLookupWarning,
} from '@linm-soft/common-components';

/** Grid cell — cột «Cho phép HT» trên danh mục TK (text từ BE). */
export function formatAccountPostingAllowedCell(a: AccountDto): string {
  if (a.disabledReason) return a.disabledReason;
  if (a.warningReason) return a.warningReason;
  const parts: string[] = [];
  if (a.allowedStandards?.trim()) parts.push(a.allowedStandards.trim());
  if (a.postingAllowedFrom) parts.push(`từ ${a.postingAllowedFrom}`);
  if (a.postingAllowedTo) parts.push(`đến ${a.postingAllowedTo}`);
  return parts.join(' · ') || '—';
}

/** ISO date YYYY-MM-DD — today local for catalog list filter. */
export function todayAsOfDateIso(): string {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

export function accountPostingWarningTitle(a: AccountDto): string | undefined {
  return getLookupWarningReason(a);
}

export function accountNeedsPostingWarning(a: AccountDto): boolean {
  return shouldShowLookupWarning(a);
}
